{
  "summary": "This paper presents CORA, a unified multilingual open question answering system that performs cross-lingual dense passage retrieval and multilingual answer generation without relying on machine translation or language-specific retrieval modules. Through iterative training and leveraging Wikipedia language links for cross-lingual data expansion, CORA achieves state-of-the-art results on multilingual QA benchmarks across many languages, including those unseen during training.",
  "strengths": [
    {
      "point": "Unified multilingual open QA model without external translation",
      "evidence": "CORA directly retrieves evidence passages from a multilingual corpus and generates answers in the target language without relying on machine translation or language-specific retrieval components."
    },
    {
      "point": "Iterative cross-lingual data expansion using Wikipedia language links",
      "evidence": "The method leverages Wikipedia language links and model predictions to automatically expand training data without additional human annotation or machine translation."
    },
    {
      "point": "Strong empirical performance across diverse languages",
      "evidence": "CORA outperforms previous state-of-the-art by 21.4 F1 points on XOR-TYDI QA and achieves improvements on MKQA, including on languages unseen during training."
    },
    {
      "point": "Detailed analysis and human evaluation",
      "evidence": "The paper provides analysis showing the importance of cross-lingual retrieval and generation, and human evaluation confirms high relevance of retrieved passages."
    }
  ],
  "weaknesses": [
    {
      "point": "Insufficient comparison to prior cross-lingual retrieval methods",
      "evidence": "The paper does not sufficiently compare to or discuss recent multilingual dense retrieval architectures or cross-lingual representation learning methods such as LaBSE or mContriever."
    },
    {
      "point": "Lack of justification for choice of pretrained models",
      "evidence": "No ablation or discussion is provided on why mBERT and mT5 were chosen over other multilingual pretrained models like XLM-R or mDeBERTa."
    },
    {
      "point": "Ablation studies do not disentangle iterative training components",
      "evidence": "The effects of Wikipedia language link-based data expansion versus model prediction-based labeling are not clearly separated in ablation experiments."
    },
    {
      "point": "Baselines may not be fully competitive",
      "evidence": "The paper does not compare against recent state-of-the-art multilingual retrieval or QA systems using advanced cross-lingual dense retrieval or multilingual generation."
    },
    {
      "point": "Evaluation metrics limited to F1 score",
      "evidence": "The evaluation relies mainly on F1 scores without additional metrics such as Exact Match, retrieval recall, or extensive human judgment."
    },
    {
      "point": "Missing training and retrieval infrastructure details",
      "evidence": "Key training hyperparameters and details on passage indexing and retrieval infrastructure (e.g., FAISS parameters) are not provided."
    },
    {
      "point": "Ambiguity in language coverage and unseen languages",
      "evidence": "The paper does not clearly define which languages are considered unseen or how many such languages were tested."
    },
    {
      "point": "Unclear mechanism of answer generator conditioning on retrieved passages",
      "evidence": "Details on how mGEN conditions on multiple retrieved passages, including passage concatenation or ranking, are insufficient."
    },
    {
      "point": "Limited discussion on handling ambiguous or unanswerable questions",
      "evidence": "The paper does not provide metrics on false positives or hallucination rates, nor mechanisms to detect generation errors in wrong languages."
    },
    {
      "point": "Evaluation limited to Wikipedia-based corpora",
      "evidence": "The method is only evaluated on Wikipedia dumps, leaving open questions about generalizability to other domains or non-Wikipedia languages."
    },
    {
      "point": "Unclear details on public release",
      "evidence": "The paper commits to releasing code and models but does not specify what exactly will be released or the timeline."
    }
  ],
  "questions": [
    {
      "question": "How does CORA compare empirically to recent multilingual dense retrieval models like LaBSE or mContriever?",
      "motivation": "Understanding comparative performance would clarify the novelty and effectiveness of the proposed retrieval approach."
    },
    {
      "question": "What is the impact of using different multilingual pretrained models for retrieval and generation?",
      "motivation": "This would inform whether the choice of mBERT and mT5 is optimal or if other models could improve performance."
    },
    {
      "question": "How does CORA handle ambiguous or genuinely unanswerable questions, and what are the hallucination rates?",
      "motivation": "This is important for assessing the reliability and usability of the system in real-world multilingual QA scenarios."
    },
    {
      "question": "Can the approach generalize beyond Wikipedia-based corpora to other domains or less structured multilingual data?",
      "motivation": "Generalizability is critical for practical deployment in diverse multilingual environments."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
